exec_args.query:
SELECT table_name
FROM information_schema.tables
WHERE table_schema = 'main';

args.query:
SELECT DISTINCT business_ref FROM review r
JOIN (
    SELECT business_ref FROM review 
    WHERE business_ref IN (
        SELECT DISTINCT business_ref 
        FROM review 
        WHERE business_ref LIKE 'businessref_%'
    )
    AND business_ref IN (
        SELECT regexp_replace(business_id, '^businessid_', 'businessref_') 
        FROM (
            SELECT business_id 
            FROM (
                SELECT business_id 
                FROM pg_temp.json_each_text('{"description": "businesses in Indianapolis, Indiana"}')
            ) subq
        ) subq2
    )
) subfilter ON r.business_ref = subfilter.business_ref
LIMIT 5;

