FROM review r
WHERE business_ref IN (
    SELECT regexp_replace(business_id, '^businessid_', 'businessref_') 
    FROM (
        SELECT business_id 
        FROM (
            SELECT 'businessid_1' as business_id 
        ) subq
        WHERE business_id LIKE 'businessid_%'
